#include <vector>
#include <algorithm>

void adaptive_sort(std::vector<int>& arr) {
    const size_t n = arr.size();
    if (n < 2) return;

    // Detect the first unsorted element
    auto it = std::is_sorted_until(arr.begin(), arr.end());
    if (it == arr.end()) {
        return;
    }

    // Optimization for nearly sorted data: if the unsorted part is small, sort and merge
    const size_t unsorted_len = static_cast<size_t>(std::distance(it, arr.end()));
    if (unsorted_len < std::max<size_t>(32, n / 16)) {
        std::sort(it, arr.end());
        std::inplace_merge(arr.begin(), it, arr.end());
        return;
    }

    // Check if the entire array is reverse sorted
    if (std::is_sorted(arr.rbegin(), arr.rend())) {
        std::reverse(arr.begin(), arr.end());
    } else {
        // Fallback for random or significantly unsorted data
        std::sort(arr.begin(), arr.end());
    }
}

